    50→// Manager is the manager of resource group.
    51→type Manager struct {
    52→	syncutil.RWMutex
    53→	cancel           context.CancelFunc
    54→	wg               sync.WaitGroup
    55→	srv              bs.Server
    56→	controllerConfig *ControllerConfig
    57→	krgms            map[uint32]*keyspaceResourceGroupManager
    58→	storage          interface {
    59→		// Used to store the resource group settings and states.
    60→		endpoint.ResourceGroupStorage
    61→		// Used to get the keyspace meta info.
