    79→}
    80→
    81→// NewManager returns a new manager base on the given server,
    82→// which should implement the `ConfigProvider` interface.
    83→func NewManager[T ConfigProvider](srv bs.Server) *Manager {
    84→	m := &Manager{
    85→		controllerConfig:      srv.(T).GetControllerConfig(),
    86→		krgms:                 make(map[uint32]*keyspaceResourceGroupManager),
    87→		consumptionDispatcher: make(chan *consumptionItem, defaultConsumptionChanSize),
    88→		keyspaceNameLookup:    make(map[uint32]string),
    89→		keyspaceIDLookup:      make(map[string]uint32),
    90→		metrics:               newMetrics(),
    91→	}
    92→	// The first initialization after the server is started.
    93→	srv.AddStartCallback(func() {
    94→		log.Info("resource group manager starts to initialize", zap.String("name", srv.Name()))
    95→		m.storage = endpoint.NewStorageEndpoint(
    96→			kv.NewEtcdKVBase(srv.GetClient()),
    97→			nil,
    98→		)
    99→		m.srv = srv
   100→	})
   101→	// The second initialization after becoming serving.
   102→	srv.AddServiceReadyCallback(m.Init)
   103→	return m
   104→}
   105→
   106→// This is used for testing only now.
   107→func (m *Manager) close() {
   108→	if m.cancel != nil {
   109→		m.cancel()
   110→	}
   111→	m.wg.Wait()
   112→}
   113→
   114→// GetBasicServer returns the basic server.
   115→func (m *Manager) GetBasicServer() bs.Server {
   116→	return m.srv
   117→}
