   124→// GetKeyspaceServiceLimiter returns the service limit of the keyspace.
   125→func (m *Manager) GetKeyspaceServiceLimiter(keyspaceID uint32) *serviceLimiter {
   126→	krgm := m.getKeyspaceResourceGroupManager(keyspaceID)
   127→	if krgm == nil {
   128→		return nil
   129→	}
   130→	return krgm.getServiceLimiter().Clone()
   131→}
   132→
   133→// SetKeyspaceServiceLimit sets the service limit of the keyspace.
   134→func (m *Manager) SetKeyspaceServiceLimit(keyspaceID uint32, serviceLimit float64) {
   135→	// If the keyspace is not found, create a new keyspace resource group manager.
   136→	m.getOrCreateKeyspaceResourceGroupManager(keyspaceID, true).setServiceLimit(serviceLimit)
   137→}
   138→
   139→func (m *Manager) getOrCreateKeyspaceResourceGroupManager(keyspaceID uint32, initDefault bool) *keyspaceResourceGroupManager {
   140→	m.Lock()
   141→	krgm, ok := m.krgms[keyspaceID]
   142→	if !ok {
   143→		krgm = newKeyspaceResourceGroupManager(keyspaceID, m.storage)
   144→		m.krgms[keyspaceID] = krgm
   145→	}
   146→	m.Unlock()
   147→	// Init the default resource group if needed.
   148→	if initDefault {
   149→		krgm.initDefaultResourceGroup()
   150→	}
   151→	return krgm
   152→}
   153→
   154→func (m *Manager) getKeyspaceResourceGroupManager(keyspaceID uint32) *keyspaceResourceGroupManager {
   155→	m.RLock()
   156→	defer m.RUnlock()
   157→	return m.krgms[keyspaceID]
   158→}
   159→
   160→func (m *Manager) accessKeyspaceResourceGroupManager(keyspaceID uint32, groupName string) (*keyspaceResourceGroupManager, error) {
   161→	var krgm *keyspaceResourceGroupManager
   162→	if groupName == DefaultResourceGroupName {
   163→		// For the default resource group, if the keyspace manager doesn't exist yet
   164→		// and the group name is the default resource group name, we try to get or create it.
   165→		krgm = m.getOrCreateKeyspaceResourceGroupManager(keyspaceID, true)
   166→	} else {
   167→		krgm = m.getKeyspaceResourceGroupManager(keyspaceID)
   168→	}
   169→	if krgm == nil {
   170→		return nil, errs.ErrKeyspaceNotExists.FastGenByArgs(keyspaceID)
   171→	}
   172→	return krgm, nil
   173→}
   174→
   175→// Init initializes the resource group manager.
   176→func (m *Manager) Init(ctx context.Context) error {
   177→	v, err := m.storage.LoadControllerConfig()
   178→	if err != nil {
   179→		log.Error("resource controller config load failed", zap.Error(err), zap.String("v", v))
   180→		return err
   181→	}
   182→	if err = json.Unmarshal([]byte(v), &m.controllerConfig); err != nil {
   183→		log.Warn("un-marshall controller config failed, fallback to default", zap.Error(err), zap.String("v", v))
   184→	}
   185→
   186→	// re-save the config to make sure the config has been persisted.
   187→	if err := m.storage.SaveControllerConfig(m.controllerConfig); err != nil {
   188→		return err
   189→	}
   190→
   191→	// Load keyspace resource groups from the storage.
   192→	if err := m.loadKeyspaceResourceGroups(); err != nil {
   193→		return err
   194→	}
   195→
   196→	// This context is derived from the leader/primary context, it will be canceled
   197→	// from the outside loop when the leader/primary step down.
   198→	ctx, m.cancel = context.WithCancel(ctx)
   199→	m.wg.Add(2)
   200→	// Start the background metrics flusher.
   201→	go m.backgroundMetricsFlush(ctx)
   202→	go func() {
   203→		defer logutil.LogPanic()
   204→		m.persistLoop(ctx)
   205→	}()
   206→	log.Info("resource group manager finishes initialization")
   207→	return nil
   208→}
   209→
   210→func (m *Manager) loadKeyspaceResourceGroups() error {
   211→	// Empty the keyspace resource group manager map before the loading.
   212→	m.Lock()
   213→	m.krgms = make(map[uint32]*keyspaceResourceGroupManager)
   214→	m.Unlock()
   215→	// Load keyspace resource group meta info from the storage.
   216→	if err := m.storage.LoadResourceGroupSettings(func(keyspaceID uint32, name string, rawValue string) {
   217→		// Since the default resource group might be loaded from the storage, we don't need to initialize it here.
   218→		err := m.getOrCreateKeyspaceResourceGroupManager(keyspaceID, false).addResourceGroupFromRaw(name, rawValue)
   219→		if err != nil {
   220→			log.Error("failed to add resource group to the keyspace resource group manager",
   221→				zap.Uint32("keyspace-id", keyspaceID), zap.String("group-name", name), zap.Error(err))
   222→		}
   223→	}); err != nil {
   224→		return err
   225→	}
   226→	// Load keyspace resource group states from the storage.
   227→	if err := m.storage.LoadResourceGroupStates(func(keyspaceID uint32, name string, rawValue string) {
   228→		krgm := m.getKeyspaceResourceGroupManager(keyspaceID)
   229→		if krgm == nil {
   230→			log.Warn("failed to get the corresponding keyspace resource group manager",
   231→				zap.Uint32("keyspace-id", keyspaceID), zap.String("group-name", name))
   232→			return
   233→		}
   234→		err := krgm.setRawStatesIntoResourceGroup(name, rawValue)
   235→		if err != nil {
   236→			log.Error("failed to set resource group state",
   237→				zap.Uint32("keyspace-id", keyspaceID), zap.String("group-name", name), zap.Error(err))
   238→		}
   239→	}); err != nil {
   240→		return err
   241→	}
   242→	// Load service limits from the storage.
   243→	if err := m.storage.LoadServiceLimits(func(keyspaceID uint32, serviceLimit float64) {
   244→		m.getOrCreateKeyspaceResourceGroupManager(keyspaceID, false).setServiceLimit(serviceLimit)
   245→	}); err != nil {
   246→		return err
   247→	}
   248→	// Initialize the reserved keyspace resource group manager and default resource groups.
   249→	m.initReserved()
   250→	return nil
   251→}
   252→
   253→func (m *Manager) initReserved() {
   254→	// Initialize the null keyspace resource group manager if it doesn't exist.
   255→	m.getOrCreateKeyspaceResourceGroupManager(constant.NullKeyspaceID, true)
   256→	// Initialize the default resource group respectively for each keyspace if it doesn't exist.
   257→	for _, krgm := range m.getKeyspaceResourceGroupManagers() {
   258→		krgm.initDefaultResourceGroup()
   259→	}
   260→}
   261→
   262→// UpdateControllerConfigItem updates the controller config item.
   263→func (m *Manager) UpdateControllerConfigItem(key string, value any) error {
   264→	kp := strings.Split(key, ".")
   265→	if len(kp) == 0 {
   266→		return errors.Errorf("invalid key %s", key)
   267→	}
   268→	m.Lock()
   269→	var config any
   270→	switch kp[0] {
   271→	case "request-unit":
   272→		config = &m.controllerConfig.RequestUnit
   273→	default:
   274→		config = m.controllerConfig
   275→	}
   276→	updated, found, err := jsonutil.AddKeyValue(config, kp[len(kp)-1], value)
   277→	if err != nil {
   278→		m.Unlock()
   279→		return err
   280→	}
   281→
   282→	if !found {
   283→		m.Unlock()
   284→		return errors.Errorf("config item %s not found", key)
   285→	}
   286→	m.Unlock()
   287→	if updated {
   288→		if err := m.storage.SaveControllerConfig(m.controllerConfig); err != nil {
   289→			log.Error("save controller config failed", zap.Error(err))
   290→		}
   291→		log.Info("updated controller config item", zap.String("key", key), zap.Any("value", value))
   292→	}
   293→	return nil
   294→}
   295→
   296→// GetControllerConfig returns the controller config.
   297→func (m *Manager) GetControllerConfig() *ControllerConfig {
   298→	m.RLock()
   299→	defer m.RUnlock()
   300→	return m.controllerConfig
   301→}
   302→
   303→// AddResourceGroup puts a resource group.
   304→// NOTE: AddResourceGroup should also be idempotent because tidb depends
   305→// on this retry mechanism.
   306→func (m *Manager) AddResourceGroup(grouppb *rmpb.ResourceGroup) error {
   307→	keyspaceID := ExtractKeyspaceID(grouppb.GetKeyspaceId())
   308→	// If the keyspace is not initialized, it means this is the first resource group created for this keyspace,
   309→	// so we need to initialize the default resource group for the keyspace as well.
   310→	krgm := m.getOrCreateKeyspaceResourceGroupManager(keyspaceID, true)
   311→	if krgm == nil {
   312→		return errs.ErrKeyspaceNotExists.FastGenByArgs(keyspaceID)
   313→	}
   314→	return krgm.addResourceGroup(grouppb)
   315→}
   316→
   317→// ModifyResourceGroup modifies an existing resource group.
   318→func (m *Manager) ModifyResourceGroup(grouppb *rmpb.ResourceGroup) error {
   319→	keyspaceID := ExtractKeyspaceID(grouppb.GetKeyspaceId())
   320→	krgm, err := m.accessKeyspaceResourceGroupManager(keyspaceID, grouppb.Name)
   321→	if err != nil {
   322→		return err
   323→	}
   324→	return krgm.modifyResourceGroup(grouppb)
   325→}
   326→
   327→// DeleteResourceGroup deletes a resource group.
   328→func (m *Manager) DeleteResourceGroup(keyspaceID uint32, name string) error {
   329→	// "default" group can't be deleted, so there is not need to call accessKeyspaceResourceGroupManager
   330→	krgm := m.getKeyspaceResourceGroupManager(keyspaceID)
   331→	if krgm == nil {
   332→		return errs.ErrKeyspaceNotExists.FastGenByArgs(keyspaceID)
   333→	}
   334→	return krgm.deleteResourceGroup(name)
   335→}
   336→
   337→// GetResourceGroup returns a copy of a resource group.
   338→func (m *Manager) GetResourceGroup(keyspaceID uint32, name string, withStats bool) (*ResourceGroup, error) {
   339→	krgm, err := m.accessKeyspaceResourceGroupManager(keyspaceID, name)
   340→	if err != nil {
   341→		return nil, err
   342→	}
   343→	return krgm.getResourceGroup(name, withStats), nil
   344→}
   345→
   346→// GetMutableResourceGroup returns a mutable resource group.
   347→func (m *Manager) GetMutableResourceGroup(keyspaceID uint32, name string) (*ResourceGroup, error) {
   348→	krgm, err := m.accessKeyspaceResourceGroupManager(keyspaceID, name)
   349→	if err != nil {
   350→		return nil, err
   351→	}
   352→	return krgm.getMutableResourceGroup(name), nil
   353→}
   354→
   355→// GetResourceGroupList returns copies of resource group list.
   356→func (m *Manager) GetResourceGroupList(keyspaceID uint32, withStats bool) ([]*ResourceGroup, error) {
   357→	krgm, err := m.accessKeyspaceResourceGroupManager(keyspaceID, DefaultResourceGroupName)
   358→	if err != nil {
   359→		return nil, err
   360→	}
   361→	return krgm.getResourceGroupList(withStats, true), nil
   362→}
   363→
   364→func (m *Manager) getRUTracker(keyspaceID uint32, name string) *ruTracker {
   365→	krgm := m.getKeyspaceResourceGroupManager(keyspaceID)
   366→	if krgm == nil {
   367→		return nil
   368→	}
   369→	return krgm.getOrCreateRUTracker(name)
   370→}
   371→
   372→func (m *Manager) persistLoop(ctx context.Context) {
   373→	defer m.wg.Done()
   374→	ticker := time.NewTicker(persistLoopInterval)
   375→	failpoint.Inject("fastPersist", func() {
   376→		ticker.Reset(100 * time.Millisecond)
   377→	})
   378→	defer ticker.Stop()
   379→	for {
   380→		select {
   381→		case <-ctx.Done():
   382→			log.Info("resource group manager persist loop exits")
   383→			return
   384→		case <-ticker.C:
   385→			for _, krgm := range m.getKeyspaceResourceGroupManagers() {
   386→				krgm.persistResourceGroupRunningState()
   387→			}
   388→		}
   389→	}
   390→}
   391→
   392→func (m *Manager) getKeyspaceResourceGroupManagers() []*keyspaceResourceGroupManager {
   393→	m.RLock()
   394→	defer m.RUnlock()
   395→	krgms := make([]*keyspaceResourceGroupManager, 0, len(m.krgms))
   396→	for _, krgm := range m.krgms {
   397→		krgms = append(krgms, krgm)
   398→	}
   399→	return krgms
   400→}
   401→
   402→func (m *Manager) dispatchConsumption(req *rmpb.TokenBucketRequest) error {
   403→	isBackground := req.GetIsBackground()
   404→	isTiFlash := req.GetIsTiflash()
   405→	if isBackground && isTiFlash {
   406→		return errors.New("background and tiflash cannot be true at the same time")
   407→	}
   408→	m.consumptionDispatcher <- &consumptionItem{
   409→		keyspaceID:        ExtractKeyspaceID(req.GetKeyspaceId()),
   410→		resourceGroupName: req.GetResourceGroupName(),
   411→		Consumption:       req.GetConsumptionSinceLastRequest(),
   412→		isBackground:      isBackground,
   413→		isTiFlash:         isTiFlash,
   414→	}
   415→	return nil
   416→}
   417→
   418→func (m *Manager) getKeyspaceNameByID(ctx context.Context, id uint32) (string, error) {
   419→	if id == constant.NullKeyspaceID {
   420→		return "", nil
   421→	}
   422→	// Try to get the keyspace name from the cache first.
   423→	m.RLock()
   424→	name, ok := m.keyspaceNameLookup[id]
   425→	m.RUnlock()
   426→	if ok {
   427→		return name, nil
   428→	}
   429→	var loadedName string
   430→	// If the keyspace name is not in the cache, try to get it from the storage.
   431→	err := m.storage.RunInTxn(ctx, func(txn kv.Txn) error {
   432→		meta, err := m.storage.LoadKeyspaceMeta(txn, id)
   433→		if err != nil {
   434→			return err
   435→		}
   436→		loadedName = meta.GetName()
   437→		return nil
   438→	})
   439→	if err != nil {
   440→		log.Error("failed to get the keyspace name", zap.Uint32("keyspace-id", id), zap.Error(err))
   441→		return "", err
   442→	}
   443→	if len(loadedName) == 0 {
   444→		return "", fmt.Errorf("got an empty keyspace name by id %d", id)
   445→	}
   446→	// Update the cache.
   447→	m.updateKeyspaceNameLookup(id, loadedName)
   448→	return loadedName, nil
   449→}
   450→
   451→func (m *Manager) updateKeyspaceNameLookup(id uint32, name string) {
   452→	m.Lock()
   453→	defer m.Unlock()
   454→	m.keyspaceNameLookup[id] = name
   455→	m.keyspaceIDLookup[name] = id
   456→}
   457→
   458→// GetKeyspaceIDByName gets the keyspace ID by name.
   459→func (m *Manager) GetKeyspaceIDByName(ctx context.Context, name string) (*rmpb.KeyspaceIDValue, error) {
   460→	if len(name) == 0 {
   461→		return &rmpb.KeyspaceIDValue{Value: constant.NullKeyspaceID}, nil
   462→	}
   463→	m.RLock()
   464→	id, ok := m.keyspaceIDLookup[name]
   465→	m.RUnlock()
   466→	if ok {
   467→		return &rmpb.KeyspaceIDValue{Value: id}, nil
   468→	}
   469→	var (
   470→		loadedID uint32
   471→		err      error
   472→	)
   473→	err = m.storage.RunInTxn(ctx, func(txn kv.Txn) error {
   474→		ok, loadedID, err = m.storage.LoadKeyspaceID(txn, name)
   475→		if err != nil {
   476→			return err
   477→		}
   478→		return nil
   479→	})
   480→	if err != nil {
   481→		log.Error("failed to get the keyspace id", zap.String("keyspace-name", name), zap.Error(err))
   482→		return nil, err
   483→	}
   484→	if !ok {
   485→		return nil, fmt.Errorf("keyspace not found with name: %s", name)
   486→	}
   487→	// Update the cache.
   488→	m.updateKeyspaceNameLookup(loadedID, name)
   489→	return &rmpb.KeyspaceIDValue{Value: loadedID}, nil
   490→}
   491→
   492→func (m *Manager) backgroundMetricsFlush(ctx context.Context) {
   493→	defer logutil.LogPanic()
   494→	defer m.wg.Done()
   495→	cleanUpTicker := time.NewTicker(metricsCleanupInterval)
   496→	defer cleanUpTicker.Stop()
   497→	metricsTicker := time.NewTicker(tickPerSecond)
   498→	defer metricsTicker.Stop()
   499→	failpoint.Inject("fastCleanupTicker", func() {
   500→		cleanUpTicker.Reset(100 * time.Millisecond)
   501→	})
   502→
   503→	for {
   504→		select {
   505→		case <-ctx.Done():
   506→			log.Info("resource group manager background metrics flush loop exits")
   507→			return
   508→		case consumptionInfo := <-m.consumptionDispatcher:
   509→			if consumptionInfo == nil || consumptionInfo.Consumption == nil {
   510→				continue
   511→			}
   512→			keyspaceID := consumptionInfo.keyspaceID
   513→			keyspaceName, err := m.getKeyspaceNameByID(ctx, keyspaceID)
   514→			if err != nil {
   515→				continue
   516→			}
   517→			now := time.Now()
   518→			sinceLastRecord := m.metrics.recordConsumption(consumptionInfo, keyspaceName, m.controllerConfig, now)
   519→			resourceGroupName := consumptionInfo.resourceGroupName
   520→			// TODO: maybe we need to distinguish background ru.
   521→			if rg, _ := m.GetMutableResourceGroup(keyspaceID, resourceGroupName); rg != nil {
   522→				rg.UpdateRUConsumption(consumptionInfo.Consumption)
   523→			}
   524→			if rt := m.getRUTracker(keyspaceID, resourceGroupName); rt != nil {
   525→				rt.sample(now, consumptionInfo.RRU+consumptionInfo.WRU, sinceLastRecord)
   526→			}
   527→		case <-cleanUpTicker.C:
   528→			// Clean up the metrics that have not been updated for a long time.
   529→			for r, lastTime := range m.metrics.consumptionRecordMap {
   530→				if time.Since(lastTime) <= metricsCleanupTimeout {
   531→					continue
   532→				}
   533→				keyspaceName, err := m.getKeyspaceNameByID(ctx, r.keyspaceID)
   534→				if err != nil {
   535→					continue
   536→				}
   537→				m.metrics.cleanupAllMetrics(r, keyspaceName)
   538→			}
   539→		case <-metricsTicker.C:
   540→			// Prevent from holding the lock too long when there're many keyspaces and resource groups.
   541→			for _, krgm := range m.getKeyspaceResourceGroupManagers() {
   542→				keyspaceName, err := m.getKeyspaceNameByID(ctx, krgm.keyspaceID)
   543→				if err != nil {
   544→					continue
   545→				}
   546→				for _, group := range krgm.getResourceGroupList(true, true) {
   547→					groupName := group.Name
   548→					// Record the sum of RRU and WRU every second.
   549→					m.metrics.getMaxPerSecTracker(krgm.keyspaceID, keyspaceName, groupName).flushMetrics()
   550→					// Skip the default resource group for the later metrics.
   551→					if groupName == DefaultResourceGroupName {
   552→						continue
   553→					}
   554→					metrics := m.metrics.getGaugeMetrics(krgm.keyspaceID, keyspaceName, groupName)
   555→					metrics.setGroup(group)
   556→					// Record the tracked RU per second.
   557→					if rt := krgm.getRUTracker(groupName); rt != nil {
   558→						metrics.setSampledRUPerSec(rt.getRUPerSec())
   559→					}
   560→				}
   561→			}
   562→		}
   563→	}
   564→}
