	testGroupSetting(&rmpb.TokenBucket{
		Tokens: 200000,
		Settings: &rmpb.TokenLimitSettings{
			FillRate:   unlimitedRate,
			BurstLimit: 0,
		},
	}, unlimitedRate, 0) // burstLimit = 0 is a special case

	testGroupSetting(&rmpb.TokenBucket{
		Tokens: 200000,
		Settings: &rmpb.TokenLimitSettings{
			FillRate:   unlimitedRate,
			BurstLimit: unlimitedBurstLimit,
