func TestTokenBucketsRequestKeyspaceBug(t *testing.T) {
	re := require.New(t)

	// Create a TokenBucketRequest without KeyspaceId
	tokenReq := &rmpb.TokenBucketRequest{
		ResourceGroupName: "test-group",
	}

	// Create a TokenBucketsRequest with the TokenBucketRequest
	bucketsReq := &rmpb.TokenBucketsRequest{
		Requests: []*rmpb.TokenBucketRequest{tokenReq},
	}

	// Test the bug: ExtractKeyspaceID should handle nil KeyspaceId
	for i, req := range bucketsReq.GetRequests() {
		keyspaceIDValue := req.GetKeyspaceId()
		keyspaceID := server.ExtractKeyspaceID(keyspaceIDValue)

		// The bug: KeyspaceId is nil, so ExtractKeyspaceID returns NullKeyspaceID
		re.Nil(keyspaceIDValue, "KeyspaceId should be nil for request %d", i)
		re.Equal(uint32(0xffffffff), keyspaceID, "ExtractKeyspaceID should return NullKeyspaceID when KeyspaceId is nil")
	}

	// Now create a TokenBucketRequest with KeyspaceId set
	tokenReqWithKeyspace := &rmpb.TokenBucketRequest{
		ResourceGroupName: "test-group-with-keyspace",
		KeyspaceId: &rmpb.KeyspaceIDValue{
			Value: 1234,
		},
	}

	bucketsReq2 := &rmpb.TokenBucketsRequest{
		Requests: []*rmpb.TokenBucketRequest{tokenReqWithKeyspace},
	}

	// Test with valid KeyspaceId
	for i, req := range bucketsReq2.GetRequests() {
		keyspaceIDValue := req.GetKeyspaceId()
		keyspaceID := server.ExtractKeyspaceID(keyspaceIDValue)

		re.NotNil(keyspaceIDValue, "KeyspaceId should not be nil for request %d", i)
		re.Equal(uint32(1234), keyspaceID, "ExtractKeyspaceID should return the correct keyspace ID")
	}
}

func TestAcquireTokenBucketsKeyspaceBug(t *testing.T) {
	re := require.New(t)

	svc := &server.Service{}
	// This test would normally require a running ResourceManager service
	// For now, we'll focus on the bug reproduction aspect

	// The bug occurs when TokenBucketsRequest doesn't have keyspace ID
	// and ExtractKeyspaceID returns NullKeyspaceID (0xffffffff)
	// which leads to empty keyspace name from getKeyspaceNameByID

	ctx := context.Background()

	// Create a request without KeyspaceId
	tokenReq := &rmpb.TokenBucketRequest{
		ResourceGroupName: "test-group",
	}

	bucketsReq := &rmpb.TokenBucketsRequest{
		Requests: []*rmpb.TokenBucketRequest{tokenReq},
	}

	// Simulate what happens in AcquireTokenBuckets
	for _, req := range bucketsReq.GetRequests() {
		keyspaceIDValue := req.GetKeyspaceId()
		keyspaceID := server.ExtractKeyspaceID(keyspaceIDValue)

		re.Nil(keyspaceIDValue, "KeyspaceId should be nil")
		re.Equal(uint32(0xffffffff), keyspaceID, "Should extract NullKeyspaceID")

		// This would result in empty keyspace name
		// getKeyspaceNameByID would return "" for NullKeyspaceID
	}
}

