package main

import (
	"fmt"
	"log"

	rmpb "github.com/pingcap/kvproto/pkg/resource_manager"
	"github.com/tikv/pd/pkg/mcs/resourcemanager/server"
)

func main() {
	// Test the fix: Create a TokenBucketRequest with KeyspaceId
	req := &rmpb.TokenBucketRequest{
		ResourceGroupName: "test-group",
		KeyspaceId:       &rmpb.KeyspaceIDValue{Value: 1234},
	}

	keyspaceIDValue := req.GetKeyspaceId()
	keyspaceID := server.ExtractKeyspaceID(keyspaceIDValue)

	fmt.Printf("TokenBucketRequest fields:\n")
	fmt.Printf("ResourceGroupName: %s\n", req.GetResourceGroupName())
	fmt.Printf("KeyspaceId: %v\n", keyspaceIDValue)
	fmt.Printf("Extracted KeyspaceID: %d\n", keyspaceID)

	if keyspaceIDValue != nil {
		fmt.Printf("KeyspaceId.Value: %d\n", keyspaceIDValue.GetValue())
	}

	// Verify the fix
	if keyspaceID != 1234 {
		log.Fatal("Fix failed: KeyspaceID not correctly set or extracted")
	}

	fmt.Println("✅ Fix verified: TokenBucketRequest now includes KeyspaceId")

	// Test with NullKeyspaceID
	reqNull := &rmpb.TokenBucketRequest{
		ResourceGroupName: "test-group-null",
	}

	keyspaceIDValueNull := reqNull.GetKeyspaceId()
	keyspaceIDNull := server.ExtractKeyspaceID(keyspaceIDValueNull)

	fmt.Printf("\nNull KeyspaceID test:\n")
	fmt.Printf("ResourceGroupName: %s\n", reqNull.GetResourceGroupName())
	fmt.Printf("KeyspaceId: %v\n", keyspaceIDValueNull)
	fmt.Printf("Extracted KeyspaceID: %d (should be 0xffffffff for NullKeyspaceID)\n", keyspaceIDNull)

	if keyspaceIDNull != 0xffffffff {
		log.Fatal("Null KeyspaceID test failed")
	}

	fmt.Println("✅ Null KeyspaceID test passed")
	fmt.Println("\n✅ All tests passed! The bug has been fixed.")
}

